/*
 * lround() test harness — prints (input_hex, output_long) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly lround  (test_lround_opt.elf)
 *   2. Linked with toolchain's default lround        (test_lround_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <limits.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    long r = lround(x);
    printf("%016llx %016lx\n", (unsigned long long)d2u(x), (unsigned long)r);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal positive */
    emit(-DBL_MIN);                 /* smallest normal negative */
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: far beyond LONG range, overflow */

    /* --- Section 4: Near 1.0 ULP neighbors (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0: rounds to 1 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0: rounds to 1 */
    emit_u(0x3feffffffff00000ULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000100000ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0: rounds to -1 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0: rounds to -1 */

    /* --- Section 5: Exact half-integer tie-breaking (lround rounds away from zero) (14) --- */
    emit(0.5);                      /* -> 1 (away from zero) */
    emit(-0.5);                     /* -> -1 (away from zero) */
    emit(1.5);                      /* -> 2 */
    emit(-1.5);                     /* -> -2 */
    emit(2.5);                      /* -> 3 */
    emit(-2.5);                     /* -> -3 */
    emit(3.5);                      /* -> 4 */
    emit(-3.5);                     /* -> -4 */
    emit(4.5);                      /* -> 5 */
    emit(-4.5);                     /* -> -5 */
    emit(100.5);                    /* -> 101 */
    emit(-100.5);                   /* -> -101 */
    emit(1000.5);                   /* -> 1001 */
    emit(-1000.5);                  /* -> -1001 */

    /* --- Section 6: Just below and above 0.5 boundary (12) --- */
    emit_u(0x3fdffffffffffffeULL);  /* just below 0.5: rounds to 0 */
    emit_u(0x3fdffffffffffffe ULL); /* 0.5 - 2 ULP */
    emit_u(0x3fe0000000000001ULL);  /* just above 0.5: rounds to 1 */
    emit_u(0xbfdffffffffffffeULL);  /* just above -0.5 (toward 0): rounds to 0 */
    emit_u(0xbfe0000000000001ULL);  /* just below -0.5 (away from 0): rounds to -1 */
    emit(0.4999999999999999);       /* just below 0.5: rounds to 0 */
    emit(0.5000000000000001);       /* just above 0.5: rounds to 1 */
    emit(-0.4999999999999999);      /* just above -0.5: rounds to 0 */
    emit(-0.5000000000000001);      /* just below -0.5: rounds to -1 */
    emit(1.4999999999999998);       /* just below 1.5: rounds to 1 */
    emit(1.5000000000000002);       /* just above 1.5: rounds to 2 */
    emit(-1.4999999999999998);      /* just above -1.5: rounds to -1 */

    /* --- Section 7: Integer-valued doubles (exact, no rounding) (10) --- */
    emit(1.0);                      /* -> 1 -- duplicate intentional for symmetry check */
    emit(2.0);
    emit(10.0);
    emit(100.0);
    emit(1000.0);
    emit(-1.0);
    emit(-2.0);
    emit(-10.0);
    emit(-100.0);
    emit(-1000.0);

    /* --- Section 8: Power-of-2 boundaries (8) --- */
    emit(0.25);                     /* 2^-2 */
    emit(0.125);                    /* 2^-3 */
    emit(4.0);                      /* 2^2 */
    emit(8.0);                      /* 2^3 */
    emit(16.0);                     /* 2^4 */
    emit(1024.0);                   /* 2^10 */
    emit(1048576.0);                /* 2^20 */
    emit(1073741824.0);             /* 2^30 */

    /* --- Section 9: Near LONG_MAX / LONG_MIN boundaries (10) --- */
    emit((double)(LONG_MAX));       /* exact LONG_MAX: may overflow depending on precision */
    emit((double)(LONG_MAX - 1));
    emit((double)(LONG_MAX - 2));
    emit((double)(LONG_MIN));       /* exact LONG_MIN */
    emit((double)(LONG_MIN + 1));
    emit((double)(LONG_MIN + 2));
    emit(2147483647.0);             /* INT_MAX (2^31-1) as double */
    emit(2147483648.0);             /* 2^31, first integer above INT_MAX */
    emit(-2147483648.0);            /* INT_MIN (-2^31) */
    emit(-2147483649.0);            /* one below INT_MIN */

    /* --- Section 10: Fractional values with non-trivial rounding (21) --- */
    emit(0.1);
    emit(0.2);
    emit(0.3);
    emit(0.4);
    emit(0.6);
    emit(0.7);
    emit(0.8);
    emit(0.9);
    emit(1.1);
    emit(1.4);
    emit(1.6);
    emit(1.9);
    emit(-0.1);
    emit(-0.4);
    emit(-0.6);
    emit(-0.9);
    emit(-1.1);
    emit(-1.4);
    emit(-1.6);
    emit(-1.9);
    emit(99.9);
}

/* ------------------------------------------------------------------ */

/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile long acc = 0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += lround(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016lx\n",
           (unsigned long long)d2u(x),
           (unsigned long)acc);
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.5);
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

